package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"
)

// mockTransformer is a simple transformer implementation for testing
type mockTransformer struct {
	transformFromFunc func(ctx context.Context, data []byte, dataCtx Context) (out []byte, stale bool, err error)
	transformToFunc   func(ctx context.Context, data []byte, dataCtx Context) (out []byte, err error)
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, stale bool, err error) {
	if m.transformFromFunc != nil {
		return m.transformFromFunc(ctx, data, dataCtx)
	}
	return data, false, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, err error) {
	if m.transformToFunc != nil {
		return m.transformToFunc(ctx, data, dataCtx)
	}
	return data, nil
}

// identityTransformer returns the input unchanged
func identityTransformer() Transformer {
	return &mockTransformer{
		transformFromFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return data, false, nil
		},
		transformToFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return data, nil
		},
	}
}

// TestTransformerRoundTrip verifies that a transformer can encrypt and decrypt data correctly
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name        string
		originalData []byte
	}{
		{
			name:         "simple string data",
			originalData: []byte("hello world"),
		},
		{
			name:         "empty data",
			originalData: []byte{},
		},
		{
			name:         "binary data with null bytes",
			originalData: []byte{0, 1, 2, 3, 255, 254, 253},
		},
		{
			name:         "large data",
			originalData: bytes.Repeat([]byte("x"), 10000),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := identityTransformer()

			// Transform to storage (encrypt)
			encrypted, err := transformer.TransformToStorage(context.Background(), tc.originalData, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Transform from storage (decrypt)
			decrypted, stale, err := transformer.TransformFromStorage(context.Background(), encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round-trip consistency
			if !bytes.Equal(decrypted, tc.originalData) {
				t.Errorf("Round-trip failed: got %v, want %v", decrypted, tc.originalData)
			}

			// Verify stale flag is false for identity transformer
			if stale {
				t.Errorf("Expected stale=false, got stale=true")
			}
		})
	}
}

// TestDefaultContext verifies the DefaultContext implementation
func TestDefaultContext(t *testing.T) {
	testCases := []struct {
		name     string
		data     []byte
	}{
		{
			name: "simple bytes",
			data: []byte("test data"),
		},
		{
			name: "empty bytes",
			data: []byte{},
		},
		{
			name: "binary data",
			data: []byte{0xFF, 0xFE, 0xFD},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.data)
			authenticated := ctx.AuthenticatedData()

			if !bytes.Equal(authenticated, tc.data) {
				t.Errorf("AuthenticatedData mismatch: got %v, want %v", authenticated, tc.data)
			}
		})
	}
}

// TestPrefixTransformerRoundTrip verifies PrefixTransformer with encryption/decryption
func TestPrefixTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name        string
		prefix      []byte
		originalData []byte
	}{
		{
			name:         "prefixed data",
			prefix:       []byte("enc:aes:"),
			originalData: []byte("sensitive data"),
		},
		{
			name:         "single byte prefix",
			prefix:       []byte("x"),
			originalData: []byte("test"),
		},
		{
			name:         "empty data with prefix",
			prefix:       []byte("prefix:"),
			originalData: []byte{},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(
				fmt.Errorf("no matching transformer"),
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: identityTransformer(),
				},
			)

			// Transform to storage
			encrypted, err := pt.TransformToStorage(context.Background(), tc.originalData, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Verify prefix was added
			if !bytes.HasPrefix(encrypted, tc.prefix) {
				t.Errorf("Expected prefix %v, encrypted data: %v", tc.prefix, encrypted)
			}

			// Transform from storage
			decrypted, stale, err := pt.TransformFromStorage(context.Background(), encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round-trip
			if !bytes.Equal(decrypted, tc.originalData) {
				t.Errorf("Round-trip failed: got %v, want %v", decrypted, tc.originalData)
			}

			// First transformer should not be stale
			if stale {
				t.Errorf("First transformer should not be stale")
			}
		})
	}
}

// TestPrefixTransformerMismatch verifies behavior when prefix doesn't match
func TestPrefixTransformerMismatch(t *testing.T) {
	testErr := fmt.Errorf("no matching transformer found")
	pt := NewPrefixTransformers(
		testErr,
		PrefixTransformer{
			Prefix:      []byte("enc:"),
			Transformer: identityTransformer(),
		},
	)

	// Try to decrypt data with wrong prefix
	data := []byte("wrong:data")
	_, _, err := pt.TransformFromStorage(context.Background(), data, nil)

	if err != testErr {
		t.Errorf("Expected error %v, got %v", testErr, err)
	}
}

// TestMultiplePrefixTransformers verifies fanout-and-select logic
func TestMultiplePrefixTransformers(t *testing.T) {
	testCases := []struct {
		name              string
		data              []byte
		expectedError     bool
		expectedStale     bool
		expectedMatchIdx  int
	}{
		{
			name:             "matches first transformer",
			data:             []byte("first:data"),
			expectedError:    false,
			expectedStale:    false,
			expectedMatchIdx: 0,
		},
		{
			name:             "matches second transformer",
			data:             []byte("second:data"),
			expectedError:    false,
			expectedStale:    true, // Non-first transformers are marked stale
			expectedMatchIdx: 1,
		},
		{
			name:             "matches third transformer",
			data:             []byte("third:data"),
			expectedError:    false,
			expectedStale:    true,
			expectedMatchIdx: 2,
		},
		{
			name:          "no match",
			data:          []byte("unknown:data"),
			expectedError: true,
			expectedStale: false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(
				fmt.Errorf("no transformer matched"),
				PrefixTransformer{
					Prefix:      []byte("first:"),
					Transformer: identityTransformer(),
				},
				PrefixTransformer{
					Prefix:      []byte("second:"),
					Transformer: identityTransformer(),
				},
				PrefixTransformer{
					Prefix:      []byte("third:"),
					Transformer: identityTransformer(),
				},
			)

			_, stale, err := pt.TransformFromStorage(context.Background(), tc.data, nil)

			if (err != nil) != tc.expectedError {
				t.Errorf("Unexpected error: got %v, expected error: %v", err, tc.expectedError)
			}

			if !tc.expectedError && stale != tc.expectedStale {
				t.Errorf("Unexpected stale flag: got %v, want %v", stale, tc.expectedStale)
			}
		})
	}
}

// TestErrorPropagation verifies that errors from transformers are propagated correctly
func TestErrorPropagation(t *testing.T) {
	transformErr := fmt.Errorf("transformation failed")
	failingTransformer := &mockTransformer{
		transformFromFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return nil, false, transformErr
		},
		transformToFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return nil, transformErr
		},
	}

	// Test TransformToStorage error propagation
	t.Run("TransformToStorage error", func(t *testing.T) {
		pt := NewPrefixTransformers(
			fmt.Errorf("default error"),
			PrefixTransformer{
				Prefix:      []byte("enc:"),
				Transformer: failingTransformer,
			},
		)

		_, err := pt.TransformToStorage(context.Background(), []byte("data"), nil)
		if err != transformErr {
			t.Errorf("Expected error %v, got %v", transformErr, err)
		}
	})

	// Test TransformFromStorage error propagation
	t.Run("TransformFromStorage error", func(t *testing.T) {
		pt := NewPrefixTransformers(
			fmt.Errorf("default error"),
			PrefixTransformer{
				Prefix:      []byte("enc:"),
				Transformer: failingTransformer,
			},
		)

		_, _, err := pt.TransformFromStorage(context.Background(), []byte("enc:data"), nil)
		if err != transformErr {
			t.Errorf("Expected error %v, got %v", transformErr, err)
		}
	})
}

// TestCorruptedDataHandling verifies behavior with corrupted/malformed data
func TestCorruptedDataHandling(t *testing.T) {
	testCases := []struct {
		name         string
		data         []byte
		shouldError  bool
	}{
		{
			name:        "valid prefixed data",
			data:        []byte("enc:corrupted"),
			shouldError: false,
		},
		{
			name:        "no prefix",
			data:        []byte("no prefix here"),
			shouldError: true,
		},
		{
			name:        "only prefix",
			data:        []byte("enc:"),
			shouldError: false,
		},
		{
			name:        "empty data",
			data:        []byte{},
			shouldError: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(
				fmt.Errorf("no matching transformer"),
				PrefixTransformer{
					Prefix:      []byte("enc:"),
					Transformer: identityTransformer(),
				},
			)

			_, _, err := pt.TransformFromStorage(context.Background(), tc.data, nil)

			if (err != nil) != tc.shouldError {
				t.Errorf("Unexpected error condition: got error=%v, expected error=%v", err != nil, tc.shouldError)
			}
		})
	}
}

// TestStaleDataDetection verifies that non-first transformers are marked stale
func TestStaleDataDetection(t *testing.T) {
	testCases := []struct {
		name             string
		matchingPrefix   []byte
		transformerIndex int
		expectedStale    bool
	}{
		{
			name:             "first transformer not stale",
			matchingPrefix:   []byte("v1:"),
			transformerIndex: 0,
			expectedStale:    false,
		},
		{
			name:             "second transformer is stale",
			matchingPrefix:   []byte("v0:"),
			transformerIndex: 1,
			expectedStale:    true,
		},
		{
			name:             "third transformer is stale",
			matchingPrefix:   []byte("legacy:"),
			transformerIndex: 2,
			expectedStale:    true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			pt := NewPrefixTransformers(
				fmt.Errorf("no matching transformer"),
				PrefixTransformer{
					Prefix:      []byte("v1:"),
					Transformer: identityTransformer(),
				},
				PrefixTransformer{
					Prefix:      []byte("v0:"),
					Transformer: identityTransformer(),
				},
				PrefixTransformer{
					Prefix:      []byte("legacy:"),
					Transformer: identityTransformer(),
				},
			)

			data := append(tc.matchingPrefix, []byte("encrypted content")...)
			_, stale, err := pt.TransformFromStorage(context.Background(), data, nil)

			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if stale != tc.expectedStale {
				t.Errorf("Expected stale=%v, got stale=%v", tc.expectedStale, stale)
			}
		})
	}
}

// TestEmptyTransformerList verifies behavior with empty transformer list
func TestEmptyTransformerList(t *testing.T) {
	customErr := fmt.Errorf("custom error message")
	pt := NewPrefixTransformers(customErr)

	// TransformFromStorage with empty list should return the custom error
	_, _, err := pt.TransformFromStorage(context.Background(), []byte("data"), nil)
	if err != customErr {
		t.Errorf("Expected custom error, got: %v", err)
	}

	// TransformToStorage with empty list should panic (accessing transformers[0])
	// This tests that the function assumes at least one transformer
	defer func() {
		if r := recover(); r == nil {
			t.Errorf("Expected panic when accessing empty transformer list in TransformToStorage")
		}
	}()
	pt.TransformToStorage(context.Background(), []byte("data"), nil)
}

// TestContextPropagation verifies that context and dataCtx are properly passed to transformers
func TestContextPropagation(t *testing.T) {
	var receivedCtx context.Context
	var receivedDataCtx Context
	testDataCtx := DefaultContext([]byte("test context data"))

	transformer := &mockTransformer{
		transformFromFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			receivedCtx = ctx
			receivedDataCtx = dataCtx
			return data, false, nil
		},
		transformToFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			receivedCtx = ctx
			receivedDataCtx = dataCtx
			return data, nil
		},
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{
			Prefix:      []byte("test:"),
			Transformer: transformer,
		},
	)

	testCtx := context.Background()

	// Test TransformToStorage context propagation
	pt.TransformToStorage(testCtx, []byte("data"), testDataCtx)
	if receivedCtx != testCtx {
		t.Errorf("Context not properly propagated to TransformToStorage")
	}
	if receivedDataCtx != testDataCtx {
		t.Errorf("DataCtx not properly propagated to TransformToStorage")
	}

	// Test TransformFromStorage context propagation
	pt.TransformFromStorage(testCtx, []byte("test:data"), testDataCtx)
	if receivedCtx != testCtx {
		t.Errorf("Context not properly propagated to TransformFromStorage")
	}
	if receivedDataCtx != testDataCtx {
		t.Errorf("DataCtx not properly propagated to TransformFromStorage")
	}
}

// TestOverlappingPrefixes verifies behavior with overlapping prefixes during error recovery
func TestOverlappingPrefixes(t *testing.T) {
	firstErr := fmt.Errorf("first transformer error")
	fallbackTransformer := &mockTransformer{
		transformFromFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return data, false, nil
		},
	}

	// Test case: first transformer with same prefix fails, second should succeed
	pt := NewPrefixTransformers(
		fmt.Errorf("default error"),
		PrefixTransformer{
			Prefix: []byte("enc:aescbc:v1:"),
			Transformer: &mockTransformer{
				transformFromFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					return nil, false, firstErr
				},
			},
		},
		PrefixTransformer{
			Prefix:      []byte("enc:aescbc:v1:"),
			Transformer: fallbackTransformer,
		},
	)

	data := []byte("enc:aescbc:v1:encrypted_content")
	result, _, err := pt.TransformFromStorage(context.Background(), data, nil)

	// Should succeed with the fallback transformer
	if err != nil {
		t.Errorf("Expected fallback transformer to succeed, got error: %v", err)
	}

	expectedResult := []byte("encrypted_content")
	if !bytes.Equal(result, expectedResult) {
		t.Errorf("Expected result %v, got %v", expectedResult, result)
	}
}

// TestPrefixTransformerUsesFirstForWrite verifies that TransformToStorage uses only the first transformer
func TestPrefixTransformerUsesFirstForWrite(t *testing.T) {
	var usedTransformerIndex int

	createTransformer := func(index int) Transformer {
		return &mockTransformer{
			transformToFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
				usedTransformerIndex = index
				return append([]byte(fmt.Sprintf("[transformer-%d]", index)), data...), nil
			},
		}
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("default error"),
		PrefixTransformer{
			Prefix:      []byte("first:"),
			Transformer: createTransformer(0),
		},
		PrefixTransformer{
			Prefix:      []byte("second:"),
			Transformer: createTransformer(1),
		},
		PrefixTransformer{
			Prefix:      []byte("third:"),
			Transformer: createTransformer(2),
		},
	)

	result, err := pt.TransformToStorage(context.Background(), []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	if usedTransformerIndex != 0 {
		t.Errorf("Expected first transformer (index 0) to be used, but transformer %d was used", usedTransformerIndex)
	}

	// Verify the first prefix was prepended
	if !bytes.HasPrefix(result, []byte("first:")) {
		t.Errorf("Expected result to have 'first:' prefix, got: %v", result)
	}
}

