	}
	return data, false, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) (out []byte, err error) {
	if m.transformToFunc != nil {
		return m.transformToFunc(ctx, data, dataCtx)
	}
	return data, nil
}

// identityTransformer returns the input unchanged
func identityTransformer() Transformer {
	return &mockTransformer{
		transformFromFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return data, false, nil
		},
		transformToFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return data, nil
		},
	}
}

// TestTransformerRoundTrip verifies that a transformer can encrypt and decrypt data correctly
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name        string
		originalData []byte
	}{
		{
			name:         "simple string data",
			originalData: []byte("hello world"),
		},
		{
			name:         "empty data",
			originalData: []byte{},
		},
		{
			name:         "binary data with null bytes",
			originalData: []byte{0, 1, 2, 3, 255, 254, 253},
		},
		{
			name:         "large data",
			originalData: bytes.Repeat([]byte("x"), 10000),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			transformer := identityTransformer()

			// Transform to storage (encrypt)
			encrypted, err := transformer.TransformToStorage(context.Background(), tc.originalData, nil)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Transform from storage (decrypt)
			decrypted, stale, err := transformer.TransformFromStorage(context.Background(), encrypted, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round-trip consistency
			if !bytes.Equal(decrypted, tc.originalData) {
				t.Errorf("Round-trip failed: got %v, want %v", decrypted, tc.originalData)
			}

			// Verify stale flag is false for identity transformer
			if stale {
				t.Errorf("Expected stale=false, got stale=true")
			}
		})
	}
}

